package main

import (
	"encoding/xml"
	"fmt"
	"io/ioutil"
	"log"
	"os"
	"strings"

	"golang.org/x/net/html"
)

type Config struct {
	Setting1 string `xml:"settingOne"`
	Setting2 string `xml:"settingTwo"`
}

func parseXML(filepath string) (*Config, error) {
	data, err := ioutil.ReadFile(filepath)
	if err != nil {
		return nil, err
	}

	doc, err := html.Parse(strings.NewReader(string(data)))
	if err != nil {
		return nil, err
	}

	var config Config
	err = xml.ElementContentNS(doc, xml.Name{Space: "", Local: "config"}, &config)
	if err != nil {
		return nil, err
	}

	return &config, nil
}

func main() {
	filepath := "./config.xml"
	config, err := parseXML(filepath)
	if err != nil {
		log.Fatalf("Error parsing XML: %v", err)
	}

	fmt.Println(config.Setting1)
	fmt.Println(config.Setting2)
}